@rendermode InteractiveServer
@implements IDisposable

<span class="theme-indicator badge rounded-pill"
      style="background-color: @(Theme?.AccentColor ?? "#0d6efd")">
    @ThemeLabel
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string ThemeLabel => Theme?.Theme switch
    {
        Theme.Dark => "🌙 Dark",
        Theme.System => "💻 System",
        _ => "☀️ Light"
    };

    public void Dispose() { }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <input type="color" class="form-control form-control-color"
                   value="@accentColor" @onchange="OnAccentChanged" />
        </div>

        <button class="btn btn-primary" @onclick="Save"
                style="background-color: @accentColor; border-color: @accentColor;">
            Save Preferences
        </button>

        @if (saved)
        {
            <span class="text-success ms-2">✓ Saved</span>
        }
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme currentTheme;
    private string accentColor = "#0d6efd";
    private bool saved;

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme;
            accentColor = Theme.AccentColor;
        }
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var t))
            currentTheme = t;
        saved = false;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
        saved = false;
    }

    private async Task Save()
    {
        var newTheme = new ThemeInfo(currentTheme, accentColor);
        await ThemeSource.NotifyChangedAsync(newTheme);
        saved = true;
    }
}

